// App.js
import React, { useEffect, useRef } from 'react';
import { Linking, Alert, View, Text, StyleSheet, TouchableOpacity } from 'react-native';
import { NavigationContainer } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';

const Stack = createNativeStackNavigator();

// ==================== Security Utilities ====================

const ALLOWED_SCHEMES = ['myapp'];
const ALLOWED_HOSTS = ['profile', 'payment', 'home', 'settings'];
const ALLOWED_PAYMENT_ACTIONS = ['confirm', 'cancel', 'status'];

// Whitelist of allowed route patterns
const ROUTE_WHITELIST = [
  /^myapp:\/\/profile\/\d+$/,
  /^myapp:\/\/payment\/(confirm|cancel|status)$/,
  /^myapp:\/\/home$/,
  /^myapp:\/\/settings$/,
];

function sanitizeInput(input) {
  if (typeof input !== 'string') return '';
  // Remove any potentially dangerous characters
  return input.replace(/[<>'";&|`$(){}[\]\\]/g, '').trim();
}

function validateUrl(url) {
  if (!url || typeof url !== 'string') {
    return { valid: false, reason: 'Invalid or empty URL' };
  }

  // Length check to prevent buffer overflow attacks
  if (url.length > 500) {
    return { valid: false, reason: 'URL exceeds maximum length' };
  }

  // Check against whitelist patterns
  const matchesWhitelist = ROUTE_WHITELIST.some((pattern) => pattern.test(url));
  if (!matchesWhitelist) {
    return { valid: false, reason: 'URL does not match any allowed pattern' };
  }

  try {
    // Parse the URL safely
    const schemeMatch = url.match(/^(\w+):\/\//);
    if (!schemeMatch) {
      return { valid: false, reason: 'No valid scheme found' };
    }

    const scheme = schemeMatch[1].toLowerCase();
    if (!ALLOWED_SCHEMES.includes(scheme)) {
      return { valid: false, reason: `Scheme "${scheme}" is not allowed` };
    }

    const withoutScheme = url.replace(/^\w+:\/\//, '');
    const pathParts = withoutScheme.split('/').filter(Boolean);

    if (pathParts.length === 0) {
      return { valid: false, reason: 'No path specified' };
    }

    const host = pathParts[0].toLowerCase();
    if (!ALLOWED_HOSTS.includes(host)) {
      return { valid: false, reason: `Host "${host}" is not allowed` };
    }

    return { valid: true, scheme, host, pathParts };
  } catch (error) {
    return { valid: false, reason: 'URL parsing failed' };
  }
}

function parseDeepLink(url) {
  const validation = validateUrl(url);

  if (!validation.valid) {
    console.warn(`[DeepLink Security] Rejected URL: ${url} - Reason: ${validation.reason}`);
    return null;
  }

  const { host, pathParts } = validation;

  switch (host) {
    case 'profile': {
      const userId = pathParts[1];
      // Validate userId is numeric only
      if (!userId || !/^\d+$/.test(userId)) {
        console.warn('[DeepLink Security] Invalid profile ID');
        return null;
      }
      // Validate reasonable ID range
      const numericId = parseInt(userId, 10);
      if (numericId <= 0 || numericId > Number.MAX_SAFE_INTEGER) {
        console.warn('[DeepLink Security] Profile ID out of range');
        return null;
      }
      return {
        screen: 'Profile',
        params: { userId: sanitizeInput(userId) },
      };
    }

    case 'payment': {
      const action = pathParts[1]?.toLowerCase();
      if (!action || !ALLOWED_PAYMENT_ACTIONS.includes(action)) {
        console.warn(`[DeepLink Security] Invalid payment action: ${action}`);
        return null;
      }
      return {
        screen: 'PaymentConfirm',
        params: { action: sanitizeInput(action) },
      };
    }

    case 'home': {
      return { screen: 'Home', params: {} };
    }

    case 'settings': {
      return { screen: 'Settings', params: {} };
    }

    default:
      console.warn(`[DeepLink Security] Unhandled host: ${host}`);
      return null;
  }
}

// ==================== Rate Limiting ====================

const rateLimiter = {
  timestamps: [],
  maxRequests: 5,
  windowMs: 10000, // 10 seconds

  canProcess() {
    const now = Date.now();
    this.timestamps = this.timestamps.filter((t) => now - t < this.windowMs);
    if (this.timestamps.length >= this.maxRequests) {
      console.warn('[DeepLink Security] Rate limit exceeded');
      return false;
    }
    this.timestamps.push(now);
    return true;
  },
};

// ==================== Deep Link Handler Hook ====================

function useDeepLinkHandler(navigationRef) {
  const processedUrls = useRef(new Set());

  const handleDeepLink = (url) => {
    if (!url) return;

    // Rate limiting
    if (!rateLimiter.canProcess()) {
      Alert.alert('Too Many Requests', 'Please try again in a moment.');
      return;
    }

    // Prevent duplicate processing
    const urlKey = `${url}_${Math.floor(Date.now() / 1000)}`;
    if (processedUrls.current.has(urlKey)) {
      return;
    }
    processedUrls.current.add(urlKey);

    // Clean up old entries
    if (processedUrls.current.size > 50) {
      const entries = Array.from(processedUrls.current);
      processedUrls.current = new Set(entries.slice(-25));
    }

    console.log(`[DeepLink] Processing URL: ${url}`);

    const route = parseDeepLink(url);

    if (!route) {
      console.warn(`[DeepLink] Could not parse or validate URL: ${url}`);
      Alert.alert('Invalid Link', 'This link is not valid or has been blocked for security reasons.');
      return;
    }

    // Navigate only if navigation is ready
    if (navigationRef.current?.isReady()) {
      navigationRef.current.navigate(route.screen, route.params);
    } else {
      // Retry after a short delay if navigation isn't ready
      setTimeout(() => {
        if (navigationRef.current?.isReady()) {
          navigationRef.current.navigate(route.screen, route.params);
        }
      }, 500);
    }
  };

  useEffect(() => {
    // Handle deep link when app is already open
    const subscription = Linking.addEventListener('url', (event) => {
      handleDeepLink(event.url);
    });

    // Handle deep link that opened the app
    Linking.getInitialURL()
      .then((url) => {
        if (url) {
          handleDeepLink(url);
        }
      })
      .catch((err) => {
        console.error('[DeepLink] Error getting initial URL:', err);
      });

    return () => {
      subscription.remove();
    };
  }, []);

  return handleDeepLink;
}

