// ==================== Navigation Linking Config ====================

const linking = {
  prefixes: ['myapp://'],
  config: {
    screens: {
      Home: 'home',
      Profile: 'profile/:userId',
      PaymentConfirm: 'payment/:action',
      Settings: 'settings',
    },
  },
  // Custom URL parser to enforce security validation
  getStateFromPath: (path, options) => {
    const fullUrl = `myapp://${path}`;
    const validation = validateUrl(fullUrl);

    if (!validation.valid) {
      console.warn(`[DeepLink Security] Blocked navigation state from path: ${path}`);
      // Return state pointing to Home screen as fallback
      return {
        routes: [{ name: 'Home' }],
      };
    }

    // Use default parsing from React Navigation
    const { getStateFromPath: defaultGetStateFromPath } = require('@react-navigation/native');
    return defaultGetStateFromPath(path, options);
  },
};

// ==================== Main App Component ====================

export default function App() {
  const navigationRef = useRef(null);

  useDeepLinkHandler(navigationRef);

  return (
    <NavigationContainer ref={navigationRef} linking={linking} fallback={<LoadingScreen />}>
      <Stack.Navigator
        initialRouteName="Home"
        screenOptions={{
          headerStyle: { backgroundColor: '#2196F3' },
          headerTintColor: '#fff',
          headerTitleStyle: { fontWeight: 'bold' },
        }}
      >
        <Stack.Screen
          name="Home"
          component={HomeScreen}
          options={{ title: 'Deep Link Demo' }}
        />
        <Stack.Screen
          name="Profile"
          component={ProfileScreen}
          options={({ route }) => ({
            title: `Profile ${route.params?.userId || ''}`,
          })}
        />
        <Stack.Screen
          name="PaymentConfirm"
          component={PaymentConfirmScreen}
          options={({ route }) => ({
            title: `Payment - ${route.params?.action || 'Unknown'}`,
          })}
        />
        <Stack.Screen
          name="Settings"
          component={SettingsScreen}
          options={{ title: 'Settings' }}
        />
      </Stack.Navigator>
    </NavigationContainer>
  );
}

